import { ChatOpenAI } from "@langchain/openai";
import { createReactAgent } from "@langchain/core/agents";
import { tool } from "@langchain/core/tools";
import { pull } from "langchain/hub";

const llm = new ChatOpenAI({ model: "gpt-4o-mini" });

const updateStatusTool = tool(async ({ userId, status }) => {
  console.log(`Updating user ${userId} to ${status}`);
  return `User ${userId} status updated to ${status}`;
}, {
  name: "update_user_status",
  description: "Update user workflow status",
  schema: {
    userId: { type: "string" },
    status: { type: "string", enum: ["pending", "approved", "rejected"] }
  }
});

const prompt = await pull("hwchase17/react");
const agent = await createReactAgent({ llm, tools: [updateStatusTool], prompt });
const result = await agent.invoke({ input: "Approve user workflow 456" });

